'use client';

import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { EmptyState } from '@/components/ui/empty-state';
import { useAuthStore } from '@/stores/auth-store';
import { useOrgStore } from '@/stores/org-store';
import { MOCK_BOARDS, MOCK_BOARD_COLUMNS, MOCK_TASKS, getProfile } from '@/lib/mock/data';

export default function BoardPage() {
  const { user, role } = useAuthStore();
  const getUserTeams = useOrgStore((s) => s.getUserTeams);

  // Get the first team's board for the current user
  const userTeams = user ? getUserTeams(user.id) : [];
  const firstTeam = userTeams[0];
  const board = role === 'owner' || role === 'admin'
    ? MOCK_BOARDS[0]
    : MOCK_BOARDS.find((b) => b.team_id === firstTeam?.id);

  if (!board) {
    return (
      <EmptyState
        title="No Board Found"
        description="You are not assigned to any team yet. Ask your admin to add you to a team."
        icon={
          <svg className="h-6 w-6 text-neutral-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7" />
          </svg>
        }
      />
    );
  }

  const columns = MOCK_BOARD_COLUMNS.filter((c) => c.board_id === board.id).sort(
    (a, b) => a.position - b.position
  );

  const getColumnTasks = (columnId: string) =>
    MOCK_TASKS.filter((t) => t.column_id === columnId && !t.is_deleted).sort(
      (a, b) => a.position - b.position
    );

  const priorityColor = (priority: string) => {
    switch (priority) {
      case 'urgent': return 'black' as const;
      case 'high': return 'black' as const;
      case 'medium': return 'neutral' as const;
      case 'low': return 'neutral' as const;
      default: return 'neutral' as const;
    }
  };

  return (
    <div>
      {/* Board header */}
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black tracking-tight text-black">{board.name}</h1>
          <p className="text-sm text-neutral-500">{board.description}</p>
        </div>
        <Badge variant="outline">{columns.length} columns</Badge>
      </div>

      {/* Kanban columns */}
      <div className="flex gap-4 overflow-x-auto pb-4">
        {columns.map((column) => {
          const tasks = getColumnTasks(column.id);
          const isOverWip = column.wip_limit !== null && tasks.length > column.wip_limit;

          return (
            <div key={column.id} className="w-72 flex-shrink-0">
              {/* Column header */}
              <div className={`mb-3 flex items-center justify-between border-b-2 ${isOverWip ? 'border-black' : 'border-neutral-300'} pb-2`}>
                <div className="flex items-center gap-2">
                  <h3 className="text-sm font-black uppercase tracking-wider text-black">
                    {column.name}
                  </h3>
                  <span className="text-xs text-neutral-400">{tasks.length}</span>
                </div>
                {column.wip_limit && (
                  <span className={`text-xs font-bold ${isOverWip ? 'text-black' : 'text-neutral-400'}`}>
                    max {column.wip_limit}
                  </span>
                )}
              </div>

              {/* Tasks */}
              <div className="space-y-3">
                {tasks.map((task) => {
                  const assignee = task.assigned_to ? getProfile(task.assigned_to) : null;

                  return (
                    <Card key={task.id} padding="sm" shadow={false} className="border-black cursor-pointer hover:shadow-[3px_3px_0px_0px_#000] transition-shadow">
                      {/* Priority + Campaign */}
                      <div className="mb-2 flex items-center gap-2">
                        <Badge color={priorityColor(task.priority)} variant={task.priority === 'urgent' ? 'filled' : 'outline'}>
                          {task.priority}
                        </Badge>
                        {task.request_status === 'pending' && (
                          <Badge color="warning" variant="outline">Pending</Badge>
                        )}
                      </div>

                      {/* Title */}
                      <h4 className="mb-1 text-sm font-bold text-black">{task.title}</h4>

                      {/* Meta */}
                      <div className="flex items-center justify-between">
                        {task.due_date && (
                          <span className="text-xs text-neutral-400">
                            Due {new Date(task.due_date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' })}
                          </span>
                        )}
                        {assignee && (
                          <div className="flex h-6 w-6 items-center justify-center rounded-full bg-black text-xs font-bold text-white" title={assignee.full_name}>
                            {assignee.full_name.split(' ').map((n) => n[0]).join('')}
                          </div>
                        )}
                      </div>
                    </Card>
                  );
                })}

                {tasks.length === 0 && (
                  <p className="py-8 text-center text-xs text-neutral-400">No tasks</p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
